import{_ as a,a as e,b as n}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as s,o as i,c,a2 as d}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"GitLab Packages Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/gitlab-packages.md","filePath":"ta/upload/gitlab-packages.md","lastUpdated":1781962217000}'),o={name:"ta/upload/gitlab-packages.md"};function r(l,t,p,h,b,g){return i(),c("div",null,[...t[0]||(t[0]=[d('<h1 id="gitlab-packages-channel-சேர்க்கவும்" tabindex="-1">GitLab Packages Channel சேர்க்கவும் <a class="header-anchor" href="#gitlab-packages-channel-சேர்க்கவும்" aria-label="Permalink to &quot;GitLab Packages Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><p>மூன்று விஷயங்கள் மட்டும்:</p><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>GitLab account</td><td>access token உருவாக்கவும் project own செய்யவும்</td></tr><tr><td>GitLab Personal Access Token</td><td>ImgBed GitLab API அணுக, projects உருவாக்க, Generic Packages-க்கு files upload செய்ய</td></tr><tr><td>Project name</td><td>project name மட்டும் கொடுக்கலாம், உதா. <code>imgbed</code></td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-gitlab-ல்-sign-in-செய்து-access-token-உருவாக்கவும்" tabindex="-1">Step 1: GitLab-ல் Sign in செய்து Access Token உருவாக்கவும் <a class="header-anchor" href="#step-1-gitlab-ல்-sign-in-செய்து-access-token-உருவாக்கவும்" aria-label="Permalink to &quot;Step 1: GitLab-ல் Sign in செய்து Access Token உருவாக்கவும்&quot;">​</a></h3><ol><li>GitLab-ல் sign in செய்யவும்.</li><li>மேல் வலது மூலையில் avatar கிளிக் செய்து <code>Preferences</code> திறக்கவும்.</li><li>left sidebar-ல் <code>Access Tokens</code> திறக்கவும்.</li><li>token-க்கு அடையாளம் காண எளிதான பெயர் கொடுக்கவும்.</li><li>maintenance preference படி expiration date தேர்வு செய்யவும்.</li><li><code>api</code> scope தேர்வு செய்யவும்.</li><li>token உருவானதும் உடனே copy செய்து சேமிக்கவும்.</li></ol><p><img src="'+a+'" alt="Create a legacy token" loading="lazy"></p><p><img src="'+e+'" alt="Select token permissions" loading="lazy"></p><h2 id="step-2-imgbed-ல்-gitlab-packages-channel-நிரப்பவும்" tabindex="-1">Step 2: ImgBed-ல் GitLab Packages Channel நிரப்பவும் <a class="header-anchor" href="#step-2-imgbed-ல்-gitlab-packages-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 2: ImgBed-ல் GitLab Packages Channel நிரப்பவும்&quot;">​</a></h2><p>Upload Settings-ல் <code>GitLab Packages</code> தேர்வு செய்த பிறகு:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>உங்கள் பெயர், உதா. <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>இப்போது உருவாக்கிய GitLab Personal Access Token.</td></tr><tr><td>Project name</td><td>short project name <code>imgbed</code>, அல்லது full path <code>username/imgbed</code>.</td></tr><tr><td>Private repository</td><td>தேவைக்கேற்ப on/off.</td></tr><tr><td>Remark</td><td>optional, உதா. <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+n+`" alt="Configure the channel" loading="lazy"></p><h2 id="step-3-channel-save-செய்யவும்" tabindex="-1">Step 3: Channel Save செய்யவும் <a class="header-anchor" href="#step-3-channel-save-செய்யவும்" aria-label="Permalink to &quot;Step 3: Channel Save செய்யவும்&quot;">​</a></h2><p>fields நிரப்பிய பிறகு Save கிளிக் செய்யவும்.</p><p>system இதை தானாக கையாளும்:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short project name</td><td>ImgBed current GitLab account கண்டறிந்து full project path ஆக expand செய்கிறது.</td></tr><tr><td>Full project path</td><td><code>username/project</code> path-ஐ உள்ளிட்டபடியே பயன்படுத்தும்.</td></tr><tr><td>Project check</td><td>current personal account path என்றால் project இல்லாதபோது ImgBed தானாக create செய்யும். full path manual என்றால் அதையே பயன்படுத்தும்.</td></tr><tr><td>Public/private state</td><td>project visibility current switch படி synchronized ஆகும்.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitLab-ல் sign in செய்யவும்</span></span>
<span class="line"><span>-&gt; Access Token உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; api scope மட்டும் தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-க்கு திரும்பி token மற்றும் project name நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; project name மட்டும் இருந்தால் ImgBed current username சேர்க்கும்</span></span>
<span class="line"><span>-&gt; username/project இருந்தால் அதையே பயன்படுத்தும்</span></span>
<span class="line"><span>-&gt; test image upload செய்யவும்</span></span></code></pre></div>`,19)])])}const P=s(o,[["render",r]]);export{k as __pageData,P as default};
